#pragma warning disable SKEXP0110 // Type is for evaluation purposes only and is subject to change or removal in future updates. Suppress this diagnostic to proceed.

    class Program
    {
        static async Task Main(string[] args)
        {
            var host = CreateHostBuilder(args).Build();

            Console.WriteLine("=== Application started. Press Ctrl+C to shut down. ===");

            var kernelService = host.Services.GetRequiredService<IKernelBuilderService>();
            Console.WriteLine($"Using AI Provider: {kernelService.CurrentProvider}\n");

            Console.WriteLine("Task: Extracting evidence for ACH step 2.\n");
            Console.WriteLine(new string('=', 70));

            try
            {
                var factory = host.Services.GetRequiredService<IOrchestrationFactory<List<Evidence>>>();

                var context = "**Jousting with Cuba over Radio Marti**\\n\\n**Case Narrative**\\n\\n**By Rudolph Rousseau**\\n\\n**Key Questions:**\\n\\n1. How was Cuban President Fidel Castro likely to react to a US decision to initiate radio broadcasts from Florida into Cuba with Radio Marti?\\n2. What could Castro do to prevent, mitigate, or delay the broadcasts?\\n3. Was his strategy in dealing with the United States likely to be fundamentally proactive or reactive?\\n4. What were the risks and benefits of initiating Radio Marti broadcasts for the Reagan administration?\\n\\n**A Modest Skirmish in a Global Confrontation**\\nBy the time US President Ronald Reagan came into office in 1981, the United States and Cuba had been in direct conflict for two decades. Over the years, Fidel Castro had used multiple measures to annoy the United States, including increasing interference with US commercial broadcasts. For example, despite Cuba’s signing of the North American Radio Broadcasting (NARB) Agreement in 1950, Cuban interference on the AM band began to grow in the 1960s after Castro came to power; by the 1970s, it was a serious problem. In 1979, Cuba submitted an inventory to the International Telecommunications Union (ITU) that included plans for two radio stations transmitting 500 kilowatts (kW) of power—a volume ten times the limit permitted to any US radio station.\\nA core objective of President Reagan\\'s national security strategy was to confront the Soviet Union and its allies globally on economic, political, and military battlefronts—both large and small. Cuba was one of the Soviet Union\\'s allies. Radio Marti was a weapon on one of those fronts.\\nAccording to a State Department official serving on the Cuban desk at the time, \\\"Breaking Cuba’s domestic monopoly of information was an important element of the Reagan administration\\'s plan to put Fidel Castro on the defensive. The collapse of the Soviet Union and its economic subsidies had already severely damaged the Cuban economy, resulting in an increase in domestic discontent. By 1980, that discontent had demonstrated that despite its capacity to project power abroad, Cuba\\'s internal social order was insecure.\\\"\\n**The Reagan administration\\'s rationale for establishing Radio Marti:**\\n\\\"To provide news, commentary, and other information about the events in Cuba and elsewhere to promote the cause of freedom in Cuba.\\\"\\nThe final phrase in that statement was a direct challenge to the Cuban regime. Although Radio Marti broadcasts would not pose the same level of threat to the Castro regime as the Bay of Pigs invasion, covert assassination plans, the tension of the Cuban Missile Crisis, or the long-standing US trade embargo, it would funnel uncontrolled information to the Cuban people.\\nAs an element of President Reagan\\'s political strategy, Radio Marti would also serve the interests of his Cuban American constituency in Florida. Reflecting these political sensitivities, the Reagan administration originally proposed that the station be operated by Radio Broadcasting to Cuba, Inc.—an independent, nonprofit corporation, incorporated in September 1981, and not under the Board for International Broadcasting, which was the parent organization of Radio Free Europe (RFE), Radio Liberty (RL), and the Voice of America (VOA).\\n\\n**A Key Intelligence Question**\\nAs the Reagan administration developed its plans for Radio Marti and Congress considered the administration\\'s legislative proposals to establish the news service, a key question was, \\\"How will Cuba respond to the new radio service?\\\" Fidel Castro\\'s response, both publicly and privately, was unequivocal. He threatened to disrupt AM broadcasting throughout the United States if the Reagan administration began Radio Marti broadcasts to Cuba.\\nIf Castro carried out his threat, US broadcasters could suffer significant economic damage. Should Congress ignore the concerns of some key constituents that the launch of Radio Marti would threaten the interests of US broadcasters, truckers, and farmers? More important, from the president\\'s perspective, the administration could be faced with the prospect of looking impotent in the face of Cuban retaliation. Should President Reagan cancel plans to launch Radio Marti to avoid any disruption of US domestic commercial radio broadcasts, or should he choose to mount a joint diplomatic and military response to deter Cuba from retaliating? Both of those options carried significant domestic political and foreign policy risk.\\n\\n**Leaders\\' Policy and Personal Stakes**\\nNational security issues are often portrayed as somewhat abstract policy choices in which the national leaders engage on an intellectual and political level. The Radio Marti proposal was a traditional national security issue. However, it also struck personal chords with Ronald Reagan, Fidel Castro, and the Cuban American community. Personal stakes can sometimes affect traditional national security calculus.\\n**President Reagan:** Before Ronald Reagan was a politician or an actor, he was a radio announcer. Between 1933 and 1937 he was a sports broadcaster on WHO, a 50 kW clear channel station broadcasting on 1040 kilohertz (kHz) located in Des Moines, Iowa, with listeners across the Midwest. In August 1981, during technical discussions concerning radio interference, Cuba said it would move forward with plans for two 500 kW stations and broadcast on 1040 kHz—the frequency designated for both Radio Marti in Florida and WHO in Iowa. On 30 August 1982, a 150 kW Cuban transmission on 1040 kHz disrupted WHO broadcasts. Fidel Castro\\'s threat to retaliate against Radio Marti directly affected Ronald Reagan\\'s radio alma mater.\\n**President Castro:** Fidel Castro, personally, and his government, generally, had been the target of US efforts to end his life and his regime since its inception in 1959. Operation Mongoose was one effort to overthrow the regime and likely had elements intended to assassinate Castro. The Bay of Pigs invasion in 1961 and the US economic embargo of Cuba in 1962 were others. Castro unquestionably perceived Radio Marti as another challenge to him personally and the success of his revolution.\\n**The Cuban American Community:** The Cuban American community in the United States was the principal advocate for Radio Marti. Many Cuban Americans had direct personal interest in the success of Radio Marti and the risks associated with initiating broadcasts. Many of the most prominent members of that community had fled Cuba after Castro came to power. A significant number had lost friends and relatives to revolutionary \\\"justice\\\" and most lost their wealth. In addition, Spanish-language radio broadcasters in south Florida had been affected by interference from Cuban stations for many years and risked additional economic damage if Castro carried out his threats to disrupt US stations in retaliation for Radio Marti\\'s broadcasts. During the 1980s, the Cuban American community had a direct and personal stake in negotiations with Cuba that could increase their access to the island and their ability to secure permission for relatives to leave.\\n\\n**Key US Stakeholders**\\nThe Reagan administration\\'s proposal to broadcast Radio Marti\\'s messages to Cuba and Fidel Castro\\'s threats to disrupt US broadcasting in response affected the interests of several politically active and potent interests in the United States.\\n**The National Association of Broadcasters (NAB):** The NAB represented commercial broadcasters across the United States. NAB members were concerned about the potential for disruption of their programs and the economic losses that would follow. The NAB had an extensive lobbying arm in Washington with ready access to members of Congress. \\nIn contrast, radio station broadcasters in south Florida, who had been affected by interference from Cuban stations for many years, generally supported Radio Marti in solidarity with their Cuban American listeners.\\n**Agricultural Interests:** Agricultural interests in the Midwest were concerned about the potential for disruption of programming important to farmers who needed reports providing agricultural information broadcast over the radio.\\n**Truckers:** Truckers who listened to clear channel radio programming during their overnight runs did not want their broadcasts disrupted.\\nMembers of Congress reflected these concerns. The south Florida delegation actively supported the Radio Marti proposal, while midwestern members who represented broadcasters, farmers, and truckers were often skeptical. In 1982, the South Florida Association of Broadcasters urged the administration to build facilities to jam Cuban radio operations until Cuban interference ended.\\n\\n**The Proposal**\\nOn 22 September 1981, President Reagan signed Executive Order 12323 to establish the Presidential Commission on Broadcasting to Cuba. The executive order was accompanied by a statement expressing the administration\\'s belief that breaking Havana\\'s information monopoly would help the Cuban people judge the Cuban revolution on its true merits.\\nThe Executive Order stated that \\\"the Commission shall develop a recommended plan for radio broadcasting intended for transmission to Cuba. The purpose of the plan shall be to promote open communication of information and ideas to Cuba and in particular broadcasting to the Cuban people of accurate information about Cuba.\\\"\\n\\n**Castro Ups the Ante**\\nThe commission, with strong representation from south Florida among its members, recommended establishing a new radio service for Cuba. On 2 February 1982, the Reagan administration introduced its proposed legislation to establish Radio Marti. The House moved quickly to establish Radio Marti as a service. H.R. 5427 was approved by the House on 10 August 1982. Radio Marti was authorized to broadcast on 1040 kHz with 50 kW of power. It would broadcast on the same frequency as WHO but would not interfere with its signal. The legislation also included a congressional provision urging the president to \\\"seek a practical political and technical solution\\\" to the threats of Cuban interference.\\nOne month before President Reagan formally announced the proposal to establish the Presidential Commission on Broadcasting to Cuba, the Cubans announced their intention to shift the frequencies of its 500 kW stations to 1040 kHz and 1160 kHz. Those frequencies represented a threat to clear channel commercial broadcasts in the United States.\\nWith the Senate Committee on Foreign Relations planning to consider the legislation, the administration appeared to be on a fast track to begin broadcasts to Cuba over Radio Marti. Then Fidel Castro placed a radio wave roadblock in the administration\\'s path. On 30 August 1982, Cuban broadcasts disrupted WHO on 1040 kHz in Des Moines, Iowa; KSL on 1160 kHz in Salt Lake City, Utah; and several other stations across the United States. At full power, Cuba’s two 500 kW transmitters could be heard in Alaska and Hawaii. \\n\\nFarmers and truckers heard the Cuban broadcasts firsthand. The NAB, citing the broadcasts, became particularly active in advocating that Congress delay implementation. Members of the Senate Committee on Foreign Relations, listening to their constituents, began to consider how best to respond.\\nThe Senate Committee modified the Radio Marti legislation and reported it out of committee on 9 September, but more importantly, on 21 December 1982, the Senate declined, by voice vote, to take up the legislation. That defeat reflected the NAB\\'s lobbying and senators\\' concerns about the potential for damage to their constituencies.\\n\\n**The Compromise**\\nRadio Marti legislation was revived at the beginning of the 98th Congress. House Foreign Affairs Committee Chairman Dante Fascell, a longtime Democratic congressman with a Miami district, presided over the hearings and eventual passage of the bill by his committee. The south Florida constituency had won a round. However, the NAB\\'s friends on the House Energy and Commerce Committee reported out another bill changing Radio Marti from a surrogate Cuban station to a more standard, objective model under the Voice of America. The same political dynamics that had led to the bill\\'s defeat in the Senate at the end of the previous Congress were reflected in this House stalemate.\\nThe administration attempted to respond to the NAB\\'s concerns by engaging the Cubans in negotiations on radio interference in August 1983. Industry representatives were part of the US delegation. These talks produced no agreement—the Cubans still opposed Radio Marti, and the Reagan administration supported it. The NAB continued to lobby against the legislation.\\nThe bill\\'s prospects in the Senate were subject to the same political dynamics leading to stalemate in the House. The bill had been reported from the Foreign Relations Committee, but Sen. Lowell Weicker, a Republican senator from Connecticut, was preventing it from moving forward. A Florida Republican, Paula Hawkins, and a Nebraska Democrat, Edward Zorinsky, convinced Weicker to accept a compromise on the legislation. They agreed to shift Radio Marti to the supervision and standards of the Voice of America and to change its frequency to 1180 kHz in order to remove the threat to WHO on 1040 kHz. The legislation was adopted by voice vote in the Senate on 13 September 1983.\\nAt this point, the Reagan administration was on the verge of having a Radio Marti, but not the Radio Marti that it originally proposed. The House was poised to pass the Senate bill with the Weicker compromise as its key provision. Then, Undersecretary of Secretary of State Lawrence Eagleburger convinced the floor manager of the bill, Chairman Dante Fascell, to make a statement prior to the bill\\'s passage that Radio Marti would be a surrogate home broadcasting service for Cuba. That legislative history would enable the administration to use Radio Marti as it intended from the beginning. Congress passed the bill and sent it to the president for his signature on 29 September. President Reagan signed the bill into law on 4 October 1983. Through the nearly three years of administration and congressional consideration of Radio Marti, Cuban opposition, intentions, and capabilities had been critical factors. The Cubans had played many of the strings of the American political instrument. However, at the end of the day, Radio Marti was established with a mandate to serve as a surrogate broadcaster to Cuba.\\n\\n**Two Questions for the US Administration**\\nAuthorization to establish Radio Marti, however, did not end the administration’s challenges. The administration needed to determine the content of the broadcasts, set up the station, hire a staff, and decide what content to include in the programming. Would Radio Marti broadcasts actively challenge the Castro regime, or would they more closely parallel Voice of America broadcasts? The Cubans had additional opportunities to influence those decisions. The field of play had now shifted from the US Congress to the executive branch.\\n\\nThe president had been clear from the beginning of his administration that he wanted Radio Marti to provide alternative information to the Cuban people. The key questions on his desk now were:\\n\\n1. How would Cuba respond to Radio Marti\\'s broadcasts?\\n2. How could the United States influence Cuba\\'s response?\\nThe first was an analytic question; the second a policy question.\\n\\n**How Would Cuba Respond?**\\nBy 1983, the principal elements of the analytic problem were well established:\\n**Open and Clandestine Sources:** Cuba had expressed its opposition to the establishment of Radio Marti clearly and consistently. Cuban opposition had been conveyed in speeches by Fidel Castro and in many other official sources. In addition, as Kenneth Skoug Jr., Cuban desk officer at the US State Department, observed, the United States had clandestine sources reporting that Cuba would take various actions to demonstrate its opposition to the broadcasts.\\n**Capabilities:** Cuba had amply demonstrated its capability to disrupt US AM broadcasting across the country. Furthermore, it had done so in response to the Radio Marti proposal.\\n**Compromise:** The Cubans had engaged in radio interference negotiations and had indicated a willingness to accept Radio Marti as another outlet of the Voice of America, largely because of the significant difference in content that would imply.\\n**Motive:** Cuba carefully controlled the regime\\'s message to the Cuban people. That effort was a critical element in its governing structure. Alternative information, particularly in times of unrest, could be a threat to the government message and program. Castro probably feared that Radio Marti could be used to help articulate grievances against the regime and to stimulate, either indirectly or directly, organized discontent. The Cubans’ motive to prevent Radio Marti from broadcasting or influencing the content of its broadcasts was clear.\\nCuba had been successful in using a combination of its disruptive broadcasting capabilities and its opposition to Radio Marti to convince significant US broadcasting, trucking, and farming interests—and the US senators who represented them—that Radio Marti, as proposed by the administration, was not worth the risk of economic damage.\\nAnalysis of Castro\\'s intentions was derived fundamentally from information from open and clandestine sources, the evaluation of Cuban capabilities to disrupt US broadcasting, and Cuba\\'s demonstrated willingness to do so. Analysts had little doubt that Castro could respond: the principal question for analysts at the time was how he would respond, and with what potential repercussions for the United States. For the administration, that was all the difference in the world.\\nCastro had been playing the great game with the United States for two decades. At times, during the Cuban Missile Crisis, for example, he had demonstrated a willingness to take aggressive and extremely risky action. During the 1970s and early 1980s, he had sent Cuban troops to Africa, Central America, and Latin America to support revolutions and was directly confronted by the United States in the process. He had lived with the impact of the US embargo at great cost to the Cuban people. That track record indicated a past willingness to engage the United States directly, but it did not establish what he would do in the case of Radio Marti.\\nThe most dispositive data concerning intentions came from reporting on the private statements of intent by Castro himself. As widely reported, Cuban Dirección General de Inteligencia (DGI) defector Major Florentino Azpillaga provided significant insights about Castro\\'s intentions to respond to Radio Marti. According to State Department Desk Officer Skoug, \\\"a very skillful use of intelligence channels would continue to hold Washington\\'s attention. US decisions about Radio Marti would be influenced by the threat of Cuban radio interference and its impact on the US broadcasting industry.\\\"\\n\\n**How Could Washington Influence Castro\\'s Behavior?**\\nThe Reagan administration estimated that Castro\\'s response to Radio Marti could be influenced by its own plans to respond to any radio interference from Cuba. The Reagan administration needed to develop a means to either persuade Castro that the costs of disrupting US radio broadcasts were too high or, if he engaged in disruption, to convince him to stop.\\nDeveloping US countermeasures to Cuban radio interference was included as a requirement in the original House-passed legislation, H.R. 5427. In addition, on 10 September 1982, in the wake of Cuba\\'s disruption of US broadcasters, Secretary of State George Shultz asked for a briefing on what countermeasures were available in the event disruptions continued. The New York Times reported that, on 7 May 1983, senior administration officials had told commercial broadcasters that a list of forty options was under consideration, including bombing antennas in Cuba if Castro jammed US radio stations.\\nDiscussions about countermeasures continued through the fall of 1983. According to Skoug, at a 19 December meeting at the White House Situation Room, he \\\"mentioned the need to have appropriate reprisals ready if Cuban reaction materialized as we feared.\\\" Skoug also wrote, \\\"In separate conversations on April 5, National Security Council staffers Constantine Menges and John Lenczowski expressed to [State Department Official] John Ferch and me a preference for military countermeasures if Cuba disrupted radio broadcasting in the United States.\\\"\\nSkoug\\'s recollections and the New York Times report provide an outline of the Reagan administration\\'s retaliatory planning if Cuba responded to Radio Marti’s startup by interfering with US commercial radio stations. The administration was not only developing plans, but by leaking their existence to the New York Times through a \\\"senior official,\\\" those plans were indirectly communicated to Cuba. As Cuba\\'s 1982 demonstration of the reach of its transmitters raised the stakes for the United States, the administration\\'s plans upped the ante for Castro.\\nTensions remained high throughout the next year. In a March 1984 interview published in the Washington Post, Cuban Vice President Carlos Rafael Rodriguez labeled Radio Marti as another US aggression and indicated that \\\"Cuban counter-broadcasting would be in proportion to the tone of Radio Marti programming.\\\"\\nWhat Washington would decide to do, however, remained an open question. As President Reagan noted in his personal diary later that year:\\n\\\"We are ready to go with Radio Marti—our station broadcasting truth to Cuba—part of our Information Program. Cuba, however, threatens retaliation; not just jamming our program but jamming AM radio stations all the way to the Midwest. They are actually completing the transmitters to do this. We can jam all of theirs but at great cost & only after several months. It will take time to set up a system. If we retreat we lose face in all of Latin America. If we go forward we could knock many of our commercial stations off the air. What to do? Right now I don’t know.\\\"\\n\\n**A Radio War with Cuba?**\\nUS analysts charged with estimating how Cuba would respond to the launch of Radio Marti had an unusually rich collection of data with which to work. The core facts were well established from multiple sources. Cuba had:\\n1. Publicly threatened to retaliate if Radio Marti began broadcasting as a surrogate radio to Cuban audiences.\\n2. Declared its possession of 500 kW transmitters to the International Telecommunication Union (ITU).\\n3. Demonstrated its capacity to use those transmitters to disrupt US commercial radio broadcasts.\\nAnalysts were also aware that general plans for aggressive countermeasures had been communicated to the Cubans. The specific operational plans were confined to a small group of White House, Intelligence Community, and Department of Defense officials. Intelligence analysts responsible for estimating Cuba\\'s response had also been directly involved in developing countermeasures.\\n\\nThe central analytic problem was to estimate what Castro would do. Would he:\\n1. Carry out his threats to retaliate and interfere with US radio broadcasts and ignore the prospect of US countermeasures?\\n2. Retaliate by taking action relating to some other aspect of US-Cuban relations?\\n3. Choose not to retaliate but only to jam incoming broadcasts, satisfied that his aggressive posture had delayed Radio Marti for more than three years and modified its content sufficiently by forcing Washington to place it under the authority of the VOA?\r\n";
                var instructions = "Tasking: Extract Evidence From the Context for ACH\\n\\n1. Objective\\n\\nYou will review the provided document (the \\\"context\\\") and produce one consolidated list of Evidence items in JSON format. This list will become the left-hand column of an Analysis of Competing Hypotheses (ACH) matrix.\\n\\nYour job is to identify facts and key assumptions only. You are not to discuss or compare hypotheses in this task.\\n\\nYour final JSON should have a single top-level key \\\"Evidence\\\" whose value is a list of objects, each with:\\n- EvidenceID: a unique integer starting at 1 and increasing by 1,\\n- Type: \\\"Fact\\\" or \\\"Assumption\\\",\\n- Description: a concise, neutral statement expressing a single idea.\\n\\n2. What Counts as Evidence\\n\\nFor this task, an Evidence item is:\\n- A Fact directly supported by the context or by well established background information, or\\n- A Key Assumption that you must treat as true to interpret the situation or connect facts.\\n\\nEach item must be:\\n- Atomic - one main idea only.\\n- Traceable - you can point to where it comes from in the context or clearly state it as an assumption.\\n- Neutral - avoids wording that embeds a conclusion or favors any hypothesis.\\n- Balanced - includes both information that could support and that could challenge plausible hypotheses.\\n\\n3. Roles\\n\\nEveryone contributes to identifying and refining Evidence items, but with different emphases:\\n- Facilitator: guides the process, manages time, keeps focus on evidence (not hypotheses), and decides when the list of Evidence is sufficient and there is no more to extract.\\n- Domain Subject-Matter Expert: clarifies context and what is operationally important, and highlights domain-relevant nuances.\\n- Textual Forensic Analyst: tracks exactly what the text says, where, and with what level of certainty, and helps phrase atomic, traceable Evidence items.\\n- Contrarian / Red-Team Analyst: challenges whether items are true evidence, checks for bias, over-interpretation, and missing disconfirming items.\\n- Assumption and Bias Auditor: surfaces hidden assumptions, labels them explicitly as Assumptions, and calls out cognitive biases in how evidence is selected or worded.\\n\\n4. Facilitator Responsibility\\n\\nAs Facilitator, you are responsible for:\\n- Keeping the group strictly focused on evidence extraction, not on arguing or evaluating hypotheses.\\n- Periodically asking whether there is any additional fact or assumption in the context that the group has not yet captured as an Evidence item.\\n- Ensuring each Evidence item is atomic, traceable, neutral, and clearly labeled as \\\"Fact\\\" or \\\"Assumption\\\".\\n- Deciding, after consulting the group, when:\\n  - The evidence list is sufficiently comprehensive,\\n  - No substantial new items are being identified, and\\n  - It is appropriate to stop extraction and finalize the Evidence JSON.\\n\\nOnce you, as Facilitator, declare the list complete, the Evidence JSON is locked and will be used as the fixed left-hand column for subsequent ACH steps.\r\n";
                var input = $"Context: {context}\nInstructions: {instructions}";

                Console.WriteLine("\nExecuting Evidence Extraction Orchestration...\n");
                Console.WriteLine($"Input: {input}", 0, 250);

                var result = await factory.ExecuteCoreAsync(input);

                Console.WriteLine("\n" + new string('=', 70));
                Console.WriteLine("\nList of Evidence");
                foreach (Evidence evidence in result)
                {
                    Console.WriteLine($"Type: {evidence.Type}\tDescription: {evidence.Description}\n");
                }
                Console.WriteLine(new string('=', 70) + "\n");
            }
            catch (Exception ex)
            {
                Console.WriteLine($"\nError: {ex.Message}");
                Console.WriteLine(ex.StackTrace);
            }
            finally
            {
                Console.WriteLine("\nPress any key to exit...");
                Console.ReadKey();
            }
        }

        public static IHostBuilder CreateHostBuilder(string[] args) =>
            Host.CreateDefaultBuilder(args)
                .ConfigureAppConfiguration((context, config) =>
                {
                    config.AddJsonFile("appsettings.json", optional: false, reloadOnChange: true);
                    config.AddJsonFile($"appsettings.{context.HostingEnvironment.EnvironmentName}.json", optional: true, reloadOnChange: true);
                    config.AddEnvironmentVariables();
                })
                .ConfigureServices((context, services) =>
                {
                    // Register configuration settings
                    services.Configure<AIServiceSettings>(context.Configuration.GetSection("AIService"));
                    services.Configure<OrchestrationSettings>(context.Configuration.GetSection("OrchestrationSettings"));

                    // Register AgentConfiguration array as a direct service (IOptions doesn't support arrays)
                    services.AddSingleton<IEnumerable<AgentConfiguration>>(sp =>
                    {
                        var config = sp.GetRequiredService<IConfiguration>();
                        return config.GetSection("AgentConfigurations").Get<AgentConfiguration[]>() ?? Array.Empty<AgentConfiguration>();
                    });

                    // Register kernel builder adapters
                    services.AddSingleton<IKernelBuilderAdapter, AzureOpenAIKernelAdapter>();
                    services.AddSingleton<IKernelBuilderAdapter, HuggingFaceKernelAdapter>();
                    services.AddSingleton<IKernelBuilderAdapter, OllamaKernelAdapter>();
                    services.AddSingleton<IKernelBuilderAdapter, OpenAIKernelAdapter>();

                    // Register kernel builder service (uses adapters)
                    services.AddSingleton<IKernelBuilderService, KernelBuilderService>();

                    // Register Kernel as a singleton using the KernelBuilderService
                    services.AddSingleton<Kernel>(sp =>
                    {
                        var kernelBuilder = sp.GetRequiredService<IKernelBuilderService>();
                        return kernelBuilder.BuildKernel();
                    });

                    // Register agent creation service (uses kernel builder service)
                    services.AddSingleton<IAgentService, AgentService>();

                    // Register orchestration factories
                    services.AddTransient<IOrchestrationFactory<List<Evidence>>, EvidenceExtractionOrchestrationFactory>();

                    // Configure logging
                    services.AddLogging(builder =>
                    {
                        builder.AddConsole();
                        builder.AddDebug();
                        builder.AddConfiguration(context.Configuration.GetSection("LoggingSettings"));
                    });
                });
    } 
}


    

